-- {"operators": "INNER_JOIN,AGGREGATE,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "WAREHOUSE,DISTRICT,CUSTOMER,OORDER,ORDER_LINE", "delta": true}
WITH cust_bal AS (SELECT C_W_ID, C_ID, C_BALANCE FROM d_CUSTOMER), order_total AS (SELECT OL_W_ID, OL_O_ID, OL_D_ID, SUM(OL_AMOUNT) AS total FROM d_ORDER_LINE GROUP BY OL_W_ID, OL_O_ID, OL_D_ID) SELECT w.W_ID, d.D_ID, cb.C_ID, cb.C_BALANCE, ot.total FROM d_WAREHOUSE w JOIN d_DISTRICT d ON w.W_ID = d.D_W_ID JOIN cust_bal cb ON d.D_W_ID = cb.C_W_ID JOIN d_OORDER o ON cb.C_W_ID = o.O_W_ID AND o.O_C_ID = cb.C_ID JOIN order_total ot ON o.O_W_ID = ot.OL_W_ID AND o.O_D_ID = ot.OL_D_ID AND o.O_ID = ot.OL_O_ID;
